const crypto = require('crypto');
const { Buffer } = require('buffer');
const raw = $input.first().json;
const body = raw.body ?? raw;

if (!body.encrypted_flow_data) {
  return [{
    json: {
      decryptionFailed: false,
      _encrypted: false,
      _aesKey: null,
      _iv: null,
      action: body.action ?? 'data_exchange',
      screen: body.screen ?? '',
      flow_token: '',
      data: body.data ?? body
    }
  }];
}

try {
  const { encrypted_flow_data, encrypted_aes_key, initial_vector } = body;
  const privateKeyPem = Buffer.from($env.WHATSAPP_FLOW_PRIVATE_KEY_ACCOUNT1, 'base64').toString('utf8');

  const decryptedAesKey = crypto.privateDecrypt(
    {
      key: crypto.createPrivateKey(privateKeyPem),
      padding: crypto.constants.RSA_PKCS1_OAEP_PADDING,
      oaepHash: 'sha256'
    },
    Buffer.from(encrypted_aes_key, 'base64')
  );

  const TAG_LENGTH = 16;
  const encryptedDataBuffer = Buffer.from(encrypted_flow_data, 'base64');
  const ivBuffer = Buffer.from(initial_vector, 'base64');
  const encryptedBody = encryptedDataBuffer.slice(0, -TAG_LENGTH);
  const authTag = encryptedDataBuffer.slice(-TAG_LENGTH);

  const decipher = crypto.createDecipheriv('aes-128-gcm', decryptedAesKey, ivBuffer);
  decipher.setAuthTag(authTag);
  const decrypted = Buffer.concat([decipher.update(encryptedBody), decipher.final()]);
  const flowData = JSON.parse(decrypted.toString('utf-8'));

  if (flowData.action === 'ping') {
    return [{
      json: {
        decryptionFailed: false,
        _encrypted: true,
        _aesKey: decryptedAesKey.toString('base64'),
        _iv: initial_vector,
        action: 'ping',
        screen: '',
        flow_token: flowData.flow_token ?? '',
        data: {}
      }
    }];
  }

  return [{
    json: {
      decryptionFailed: false,
      _encrypted: true,
      _aesKey: decryptedAesKey.toString('base64'),
      _iv: initial_vector,
      action: flowData.action,
      screen: flowData.screen,
      flow_token: flowData.flow_token ?? '',
      data: flowData.data
    }
  }];

} catch (err) {
  const errorMessage = err instanceof Error ? err.message : String(err);
  return [{
    json: {
      decryptionFailed: true,
      error: errorMessage
    }
  }];
}

const crypto = require('crypto');
const { Buffer } = require('buffer');
const { _aesKey, _iv, _encrypted, error } = $input.first().json;
const response = {
  error: {
    error_msg: error || 'Validation error',
    error_code: 'VALIDATION_ERROR'
  }
};

if (!_encrypted) {
  return [{ json: { responseBody: JSON.stringify(response) } }];
}

const aesKeyBuffer = Buffer.from(_aesKey, 'base64');
const ivBuffer = Buffer.from(_iv, 'base64');
const flippedIv = ivBuffer.map(b => ~b & 0xff);

const cipher = crypto.createCipheriv('aes-128-gcm', aesKeyBuffer, Buffer.from(flippedIv));
const encrypted = Buffer.concat([
  cipher.update(JSON.stringify(response), 'utf-8'),
  cipher.final(),
  cipher.getAuthTag()
]);

return [{ json: { responseBody: encrypted.toString('base64') } }];

const raw = $input.first().json;
const body = raw.data ?? raw;
const _aesKey = raw._aesKey;
const _iv = raw._iv;
const _encrypted = raw._encrypted;
const telefono_principal = raw.flow_token ?? '';

const REQUERIDOS = [
  'nombre_alumno',
  'apellido_alumno',
  'telefono_alternativo',
  'correo_alumno',
  'escuela',
  'nivel_educativo',
  'tutor',
  'tiene_cud',
  'realiza_tratamiento'
  ];

const faltantes = REQUERIDOS.filter(campo => !body[campo]);
if (faltantes.length > 0) {
  return [{
    json: {
    exito: false,
    error: `Campos requeridos faltantes: ${faltantes.join(', ')}`,
    _aesKey, _iv, _encrypted,
    datos: body
    }
  }];
}

  if (body.tiene_cud === 'si' && !body.condicion_alumno) {
    return [{
      json: {
        exito: false,
        error: 'Se indicó CUD pero falta el diagnóstico o condición del alumno',
        _aesKey, _iv, _encrypted
      }
    }];
  }

const tipos = Array.isArray(body.tipos_tratamiento) ? body.tipos_tratamiento : [];

return [{
  json: {
    exito: true,
    _aesKey, _iv, _encrypted, telefono_principal,
    nombre_alumno: body.nombre_alumno,
    apellido_alumno: body.apellido_alumno,
    telefono_alternativo: body.telefono_alternativo,
    correo_alumno: body.correo_alumno,
    escuela: body.escuela,
    nivel_educativo: body.nivel_educativo,
    tutor: body.tutor,
    tiene_cud: body.tiene_cud === 'si',
    condicion_alumno: body.condicion_alumno || '',
    realiza_tratamiento: body.realiza_tratamiento === 'si',
    psicopedagoga: tipos.includes('psicopedagoga'),
    fono: tipos.includes('fono'),
    psicologo: tipos.includes('psicologo'),
    teo: tipos.includes('teo')
  }
}];

